package com.hospital.management.dao.impl;import com.hospital.management.dao.PrescriptionItemDao;import com.hospital.management.model.PrescriptionItem;import com.hospital.management.util.DatabaseConnectionManager;import java.sql.*;import java.util.*;
public class PrescriptionItemDaoImpl implements PrescriptionItemDao {public List<PrescriptionItem>findByPrescriptionId(Long id)throws SQLException{if(id==null)return List.of();try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement("SELECT * FROM PRESCRIPTION_ITEMS WHERE PRESCRIPTION_ID=? ORDER BY PRESCRIPTION_ITEM_ID")){s.setLong(1,id);List<PrescriptionItem>x=new ArrayList<>();try(ResultSet r=s.executeQuery()){while(r.next())x.add(map(r));}return x;}}public long createItem(Connection c,PrescriptionItem i)throws SQLException{try(PreparedStatement s=c.prepareStatement("INSERT INTO PRESCRIPTION_ITEMS(PRESCRIPTION_ID,MEDICINE_NAME,DOSAGE,FREQUENCY,DURATION,ROUTE,INSTRUCTIONS)VALUES(?,?,?,?,?,?,?)",new String[]{"PRESCRIPTION_ITEM_ID"})){s.setLong(1,i.getPrescriptionId());s.setString(2,i.getMedicineName());s.setString(3,i.getDosage());s.setString(4,i.getFrequency());s.setString(5,i.getDuration());s.setString(6,i.getRoute());s.setString(7,i.getInstructions());s.executeUpdate();try(ResultSet r=s.getGeneratedKeys()){return r.next()?r.getLong(1):0;}}}public int deleteByPrescriptionId(Connection c,Long id)throws SQLException{try(PreparedStatement s=c.prepareStatement("DELETE FROM PRESCRIPTION_ITEMS WHERE PRESCRIPTION_ID=?")){s.setLong(1,id);return s.executeUpdate();}}private PrescriptionItem map(ResultSet r)throws SQLException{PrescriptionItem i=new PrescriptionItem();i.setPrescriptionItemId(r.getLong("PRESCRIPTION_ITEM_ID"));i.setPrescriptionId(r.getLong("PRESCRIPTION_ID"));i.setMedicineName(r.getString("MEDICINE_NAME"));i.setDosage(r.getString("DOSAGE"));i.setFrequency(r.getString("FREQUENCY"));i.setDuration(r.getString("DURATION"));i.setRoute(r.getString("ROUTE"));i.setInstructions(r.getString("INSTRUCTIONS"));Timestamp t=r.getTimestamp("CREATED_AT");i.setCreatedAt(t==null?null:t.toLocalDateTime());return i;}}
